import{transformersPV}from"../util/transformers";import{valueTransform}from"../util/ValueTransformer";export default function handlePVPacket(data){const idx=data.indexOf(0);if(idx!==-1){const key=data.slice(0,idx).toString();const partA=data.slice(idx+1,idx+1+2);const partB=data.slice(idx+1+2);const value=valueTransform(key,partB,transformersPV);data={name:key,value,partA,partB}}else{console.warn("Could parse PV packet",data)}return data}